sql:
SELECT vcenter_name, vcenter_status, vcenter_datacenter
FROM vcenters
WHERE vcenter_status = 'online';

SELECT esxi_name
FROM esxi_hosts
WHERE esxi_is_unavailable = 0;

SELECT esxi_name
FROM esxi_hosts
ORDER BY esxi_name ASC;

SELECT COUNT(*) AS unavailable_esxi_hosts
FROM esxi_hosts
WHERE esxi_is_unavailable = 1;

SELECT COUNT(vcenter_id) AS vcenter_count
FROM vcenters
WHERE vcenter_status = 'online';

external_knowledge:
- "Available" refers to vCenter servers, ESXi hosts, and virtual machines with their respective "is_unavailable" flags set to 0; 
- "top three virtual machines" refers to the virtual machines with the highest memory information, ranked in descending order; 
- "physical hosts with over 128 GB of memory" refers to physical hosts with memory information greater than 128 GB.

sql:
SELECT esxi_name, COUNT(*) AS host_count
FROM esxi_hosts
GROUP BY esxi_name;
